import json, sys, os, subprocess
try:
    data = json.load(sys.stdin)
    tool_input = data.get('tool_input') or {}
    cmd = tool_input.get('command', '') if isinstance(tool_input, dict) else ''
    if not cmd:
        sys.exit(0)
    # Notify on git operations
    if cmd.startswith('git '):
        parts = cmd.split()
        op = parts[1] if len(parts) > 1 else 'operation'
        if op in ['add', 'commit', 'push', 'pull', 'merge', 'rebase']:
            subprocess.run(['osascript', '-e', f'display notification "Git {op} completed" with title "Claude Code"'], capture_output=True)
    # Notify on xcodebuild
    if 'xcodebuild' in cmd:
        subprocess.run(['osascript', '-e', 'display notification "Build completed" with title "Xcode"'], capture_output=True)
except Exception:
    pass
sys.exit(0)
